---
import BaseLayout from '../layouts/BaseLayout.astro';
import type { Locale } from '../i18n';
const { locale } = Astro.props as { locale: Locale }; const pt = locale === 'pt';
const x = pt ? {
 title:'ESAA — Event Sourcing for Autonomous Agents', description:'Um protocolo event-sourced para governar agentes autônomos com contratos, evidência e projeções determinísticas.', alternate:'/en/esaa/',
 label:'Event Sourcing for Autonomous Agents', headline:'Agentes propõem. O protocolo decide.', lede:'ESAA transforma execução autônoma em um processo governado: cada intenção é validada, registrada e projetada antes de produzir efeitos.',
 why:'Autonomia sem memória verificável é apenas velocidade com risco.', whyText:'Agentes são probabilísticos. Sistemas operacionais precisam de regras determinísticas. O ESAA separa esses dois mundos para que decisões possam ser auditadas, reproduzidas e revisadas.',
 architecture:'Uma fonte da verdade. Muitas visões confiáveis.', workflow:'O trabalho avança por transições explícitas.', quick:'Comece com um workspace limpo.', runners:'Runners são identificados; autoridade continua no protocolo.', trust:'Confiança é uma propriedade verificável.', docs:'Continue pelos artefatos canônicos.'
} : {
 title:'ESAA — Event Sourcing for Autonomous Agents', description:'An event-sourced protocol for governing autonomous agents with contracts, evidence and deterministic projections.', alternate:'/esaa/',
 label:'Event Sourcing for Autonomous Agents', headline:'Agents propose. The protocol decides.', lede:'ESAA turns autonomous execution into a governed process: every intent is validated, recorded and projected before producing effects.',
 why:'Autonomy without verifiable memory is speed carrying risk.', whyText:'Agents are probabilistic. Operational systems need deterministic rules. ESAA separates both worlds so decisions can be audited, reproduced and reviewed.',
 architecture:'One source of truth. Many dependable views.', workflow:'Work moves through explicit transitions.', quick:'Start with a clean workspace.', runners:'Runners are identified; authority remains in the protocol.', trust:'Trust is a verifiable property.', docs:'Continue through the canonical artifacts.'
};
const labels = pt ? ['Visão','Por quê','Arquitetura','Fluxo','Quickstart','Runners','Trust','Docs'] : ['Overview','Why','Architecture','Workflow','Quickstart','Runners','Trust','Docs'];
---
<BaseLayout title={x.title} description={x.description} locale={locale} alternate={x.alternate} section="esaa" image="/esaa-card.svg">
 <nav class="esaa-nav" aria-label={pt?'Navegação ESAA':'ESAA navigation'}>{['overview','why','architecture','workflow','quickstart','runners','trust','docs'].map((id,i)=><a href={`#${id}`}>{labels[i]}</a>)}</nav>
 <section class="esaa-hero" id="overview"><div class="wrap"><p class="protocol">ESAA / PROTOCOL 0.4.1</p><h1>{x.headline}</h1><p>{x.lede}</p><div class="actions"><a class="button esaa-button" href="#quickstart">{pt?'Ver quickstart':'View quickstart'}</a><a class="button secondary" href="https://github.com/elzobrito/ESAA-Core">GitHub ↗</a></div><div class="signal"><span>AGENT</span><i>proposes</i><span>ORCHESTRATOR</span><i>records</i><span>EVENT STORE</span><i>projects</i><span>READ MODELS</span></div></div></section>
 <section class="esaa-section wrap" id="why"><p class="protocol">01 / WHY</p><h2>{x.why}</h2><p class="big-copy">{x.whyText}</p><div class="principles"><article><b>01</b><h3>{pt?'Intenção, não acesso irrestrito':'Intent, not unrestricted access'}</h3><p>{pt?'Agentes emitem resultados estruturados sob contrato.':'Agents emit structured results under contract.'}</p></article><article><b>02</b><h3>Single writer</h3><p>{pt?'Somente o Orchestrator admite eventos e aplica efeitos.':'Only the Orchestrator admits events and applies effects.'}</p></article><article><b>03</b><h3>{pt?'História imutável':'Immutable history'}</h3><p>{pt?'Tarefas concluídas não são reescritas; correções viram novos eventos.':'Completed tasks are not rewritten; corrections become new events.'}</p></article></div></section>
 <section class="esaa-section architecture" id="architecture"><div class="wrap"><p class="protocol">02 / ARCHITECTURE</p><h2>{x.architecture}</h2><div class="architecture-grid"><div class="flow-box"><div><strong>Agent</strong><small>{pt?'intenção JSON':'JSON intent'}</small></div><span>→</span><div class="active"><strong>Orchestrator</strong><small>{pt?'valida + aplica':'validates + applies'}</small></div><span>→</span><div><strong>Event Store</strong><small>append-only log</small></div><span>→</span><div><strong>Projections</strong><small>roadmap · issues · lessons</small></div></div><p>{pt?'O event store append-only é a fonte canônica. Roadmap, issues e lessons são projeções reconstruíveis — úteis para leitura, nunca para edição manual.':'The append-only event store is canonical. Roadmap, issues and lessons are rebuildable projections — useful for reading, never for manual editing.'}</p></div></div></section>
 <section class="esaa-section wrap" id="workflow"><p class="protocol">03 / WORKFLOW</p><h2>{x.workflow}</h2><p class="workflow-intro">{pt?'Acompanhe uma tarefa atravessar o protocolo. Cada transição admite um novo evento; activity.jsonl preserva a história e o roadmap reflete o estado atual.':'Watch a task move through the protocol. Each transition admits a new event; activity.jsonl preserves history while the roadmap reflects the current state.'}</p>
  <div class="runtime-demo" data-esaa-demo data-locale={locale}>
   <header class="runtime-head"><div><span class="live-dot"></span><span>ESAA RUNTIME / LIVE</span></div><div class="runtime-controls"><button type="button" data-demo-toggle>{pt?'Pausar':'Pause'}</button><button type="button" data-demo-replay>{pt?'Reiniciar':'Replay'}</button></div></header>
   <div class="runtime-stage">
    <div class="runtime-main">
     <div class="task-title"><span>TASK</span><strong>SITE-DEMO-001</strong><em data-demo-status>todo</em></div>
     <div class="animated-machine" aria-label={pt?'Máquina de estados animada':'Animated state machine'}>
      {['todo','in_progress','review','done'].map((state,i)=><div class="animated-state" data-demo-state={i}><span>0{i+1}</span><strong>{state}</strong><small>{['claim','complete','review','immutable'][i]}</small></div>)}
     </div>
     <div class="event-stream"><div class="panel-label"><span>ACTIVITY.JSONL</span><span>APPEND ONLY</span></div><ol aria-live="polite"><li data-demo-event="0"><time>10:42:01</time><b>TASK</b><code>task.created</code></li><li data-demo-event="1"><time>10:42:03</time><b>CLAIM</b><code>task.claimed · agent-impl</code></li><li data-demo-event="2"><time>10:42:08</time><b>OUTPUT</b><code>task.completed · 2 files</code></li><li data-demo-event="3"><time>10:42:11</time><b>REVIEW</b><code>review.approved · agent-qa</code></li></ol></div>
    </div>
    <aside class="projection-panel"><div class="panel-label"><span>ROADMAP PROJECTION</span><span data-projection-sync>SYNCED</span></div><div class="projection-counts"><div><small>TODO</small><strong data-count="todo">1</strong></div><div><small>ACTIVE</small><strong data-count="active">0</strong></div><div><small>REVIEW</small><strong data-count="review">0</strong></div><div><small>DONE</small><strong data-count="done">0</strong></div></div><div class="projection-card"><span data-roadmap-line>status: todo</span><span>assigned_to: <i data-roadmap-agent>null</i></span><span>event_seq: <i data-roadmap-seq>1041</i></span><span>projection_hash: <i data-roadmap-hash>9f2a…71c0</i></span></div><p>{pt?'O roadmap não é editado: ele é reconstruído a partir dos eventos admitidos.':'The roadmap is not edited: it is rebuilt from admitted events.'}</p></aside>
   </div>
   <footer class="runtime-stats"><div><span>{pt?'EVENTOS ADMITIDOS':'EVENTS ADMITTED'}</span><strong data-event-count>1</strong></div><div><span>{pt?'PROJEÇÃO':'PROJECTION'}</span><strong data-projection-state>{pt?'ATUAL':'CURRENT'}</strong></div><div><span>{pt?'CADEIA':'CHAIN'}</span><strong>VERIFIED</strong></div></footer>
  </div>
  <aside class="receipt"><span>VERIFIED RECEIPT</span><code>task_id: SITE-DEMO-001<br/>actor: agent-qa<br/>runner: codex<br/>checks: 3 passed<br/>review: approved<br/>event_seq: 1044<br/>chain: verified</code></aside>
 </section>
 <section class="esaa-section quick" id="quickstart"><div class="wrap"><p class="protocol">04 / QUICKSTART</p><h2>{x.quick}</h2><pre><code>python -m pip install --upgrade --pre esaa-core
mkdir esaa-demo && cd esaa-demo
esaa bootstrap --profile public
esaa init
esaa verify
esaa eligible</code></pre><p>{pt?'O primeiro sinal esperado é verify_status: ok. O runtime opera localmente sobre o diretório de governança e não exige MCP.':'The first expected signal is verify_status: ok. The runtime operates locally over the governance directory and does not require MCP.'}</p></div></section>
 <section class="esaa-section wrap" id="runners"><p class="protocol">05 / RUNNERS</p><h2>{x.runners}</h2><div class="runner-grid"><article><span>codex</span><b>runner_id</b><p>{pt?'Proveniência em cada evento admitido.':'Provenance on every admitted event.'}</p></article><article><span>claude-code</span><b>runner_id</b><p>{pt?'O mesmo contrato, independentemente da superfície.':'The same contract regardless of surface.'}</p></article><article><span>local-script</span><b>runner_id</b><p>{pt?'Automação determinística também deixa recibos.':'Deterministic automation leaves receipts too.'}</p></article></div></section>
 <section class="esaa-section trust" id="trust"><div class="wrap"><p class="protocol">06 / TRUST</p><h2>{x.trust}</h2><ul><li><b>Append-only</b><span>{pt?'Eventos ordenados e sem edição manual.':'Ordered events without manual editing.'}</span></li><li><b>Replay</b><span>{pt?'Estado reconstruído a partir da história.':'State rebuilt from history.'}</span></li><li><b>Hash</b><span>{pt?'Projeções verificadas contra a fonte.':'Projections verified against the source.'}</span></li><li><b>Fail-closed</b><span>{pt?'Saídas inválidas são rejeitadas antes dos efeitos.':'Invalid outputs are rejected before effects.'}</span></li></ul></div></section>
 <section class="esaa-section wrap" id="docs"><p class="protocol">07 / DOCS</p><h2>{x.docs}</h2><div class="grid"><a class="card" href="https://github.com/elzobrito/ESAA-Core"><span class="tag">SOURCE</span><h3>ESAA-Core</h3><p>{pt?'Runtime, contratos, schemas e testes de referência.':'Reference runtime, contracts, schemas and tests.'}</p></a><a class="card" href="https://github.com/elzobrito/ESAA-Core/tree/main/docs/guides"><span class="tag">GUIDES</span><h3>{pt?'Guias práticos':'Practical guides'}</h3><p>Getting started, cookbook, CLI e runners.</p></a><a class="card" href="https://arxiv.org/pdf/2602.23193"><span class="tag">PAPER</span><h3>{pt?'Fundamentação':'Foundations'}</h3><p>{pt?'A arquitetura e suas motivações em formato acadêmico.':'The architecture and its motivations in academic form.'}</p></a></div></section>
</BaseLayout>
<style>
 .esaa-nav{position:sticky;top:72px;z-index:15;display:flex;justify-content:center;gap:1.4rem;padding:.7rem 1rem;overflow-x:auto;background:var(--ink);color:var(--paper);font-family:var(--mono);font-size:.68rem}.esaa-nav a{text-decoration:none;white-space:nowrap}.esaa-hero{min-height:82vh;display:grid;align-items:center;background:linear-gradient(135deg,color-mix(in srgb,var(--esaa) 14%,var(--paper)),var(--paper));overflow:hidden}.esaa-hero .wrap{min-width:0}.esaa-hero h1{font-family:var(--serif);font-size:clamp(3.8rem,10vw,9rem);line-height:.85;letter-spacing:-.07em;max-width:1100px;margin:1.5rem 0;overflow-wrap:break-word}.esaa-hero>div>p:not(.protocol){max-width:700px;font-size:1.3rem;color:var(--muted)}.protocol{font-family:var(--mono);letter-spacing:.13em;font-size:.7rem;color:var(--esaa);font-weight:800}.esaa-button{background:var(--esaa);border-color:var(--esaa)}.signal{display:flex;align-items:center;gap:.8rem;margin-top:5rem;font-family:var(--mono);font-size:.67rem;white-space:nowrap;max-width:100%;overflow-x:auto}.signal span{border:1px solid var(--line);padding:.5rem}.signal i{color:var(--muted)}.esaa-section{padding-block:7rem;scroll-margin-top:120px}.esaa-section h2{font-family:var(--serif);font-size:clamp(2.7rem,7vw,6.5rem);line-height:.92;letter-spacing:-.06em;max-width:1000px}.big-copy{font-size:clamp(1.2rem,2.6vw,2rem);max-width:850px;color:var(--muted)}.principles,.runner-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1px;background:var(--line);border:1px solid var(--line);margin-top:4rem}.principles article,.runner-grid article{background:var(--surface);padding:2rem}.principles b{font-family:var(--mono);color:var(--esaa)}.principles h3{margin-top:4rem}.architecture,.quick,.trust{background:var(--ink);color:var(--paper)}.architecture-grid>p,.quick p{color:#aaa;max-width:740px}.flow-box{display:flex;align-items:center;justify-content:space-between;gap:1rem;margin:4rem 0}.flow-box div{border:1px solid #444;padding:1.2rem;display:grid;gap:.4rem;min-width:160px}.flow-box .active{border-color:var(--esaa);box-shadow:0 0 0 3px color-mix(in srgb,var(--esaa) 25%,transparent)}.flow-box small{color:#aaa}.workflow-intro{max-width:760px;color:var(--muted);font-size:1.08rem}.runtime-demo{--runtime-accent:#46d99b;margin:4rem 0 2rem;background:#0c0d0c;color:#e8ece9;border:1px solid #2b302d;border-radius:18px;overflow:hidden;font-family:var(--mono);box-shadow:0 28px 80px rgba(0,0,0,.18)}.runtime-head,.runtime-stats{display:flex;align-items:center;justify-content:space-between;padding:1rem 1.25rem;border-bottom:1px solid #252a27;font-size:.67rem;letter-spacing:.12em}.runtime-head>div:first-child{display:flex;align-items:center;gap:.65rem}.live-dot{width:.48rem;height:.48rem;border-radius:50%;background:var(--runtime-accent);box-shadow:0 0 0 5px rgba(70,217,155,.08);animation:livePulse 1.8s infinite}.runtime-controls{display:flex;gap:.5rem}.runtime-controls button{appearance:none;border:1px solid #343a36;background:#151816;color:#bfc6c1;padding:.48rem .72rem;border-radius:6px;font:inherit;letter-spacing:.06em;cursor:pointer}.runtime-controls button:hover,.runtime-controls button:focus-visible{border-color:var(--runtime-accent);color:#fff}.runtime-stage{display:grid;grid-template-columns:minmax(0,1.55fr) minmax(280px,.75fr)}.runtime-main{padding:1.4rem;border-right:1px solid #252a27}.task-title{display:flex;align-items:center;gap:.8rem;padding-bottom:1.4rem}.task-title>span{color:#737b76;font-size:.62rem;letter-spacing:.12em}.task-title strong{font-size:.78rem}.task-title em{margin-left:auto;background:#224b3a;color:#9bf4cd;padding:.38rem .6rem;font-size:.66rem;font-style:normal}.animated-machine{display:grid;grid-template-columns:repeat(4,1fr);gap:1px;background:#252a27;border:1px solid #252a27}.animated-state{position:relative;display:grid;gap:.5rem;min-width:0;padding:1rem;background:#111311;opacity:.36;transition:opacity .35s,background .35s,box-shadow .35s}.animated-state:not(:last-child)::after{content:'›';position:absolute;right:-.42rem;top:50%;z-index:2;color:#5d655f;transform:translateY(-50%);font-size:1.2rem}.animated-state span,.animated-state small{color:#737b76;font-size:.6rem}.animated-state strong{font-size:.72rem;overflow-wrap:anywhere}.animated-state.is-past{opacity:.62}.animated-state.is-active{opacity:1;background:#153527;box-shadow:inset 0 0 0 1px var(--runtime-accent)}.animated-state.is-active span,.animated-state.is-active small{color:#9bf4cd}.event-stream{margin-top:1.4rem;border:1px solid #252a27}.panel-label{display:flex;justify-content:space-between;gap:1rem;padding:.75rem 1rem;border-bottom:1px solid #252a27;color:#717a74;font-size:.58rem;letter-spacing:.13em}.event-stream ol{list-style:none;margin:0;padding:.75rem 1rem;min-height:174px}.event-stream li{display:grid;grid-template-columns:76px 72px 1fr;gap:.65rem;padding:.43rem 0;color:#68706b;font-size:.66rem;opacity:.18;transform:translateY(5px);transition:opacity .35s,transform .35s,color .35s}.event-stream li.is-visible{opacity:1;transform:none;color:#c9d0cb}.event-stream li.is-current b,.event-stream li.is-current code{background:#20543d;color:#b6f8d8}.event-stream b,.event-stream code{width:max-content;padding:.12rem .28rem;font:inherit}.projection-panel{padding:1.4rem}.projection-panel>.panel-label{padding:0 0 .85rem}.projection-counts{display:grid;grid-template-columns:repeat(2,1fr);gap:1px;margin-top:1rem;background:#252a27;border:1px solid #252a27}.projection-counts div{display:grid;gap:.4rem;background:#111311;padding:.85rem}.projection-counts small{color:#737b76;font-size:.58rem}.projection-counts strong{font-size:1.35rem;font-weight:500}.projection-card{display:grid;gap:.7rem;margin-top:1rem;padding:1rem;background:#111311;border:1px solid #252a27;color:#8e9891;font-size:.64rem}.projection-card i{font-style:normal;color:#d1d7d3}.projection-panel p{color:#737b76;font-family:var(--sans);font-size:.8rem;line-height:1.6}.runtime-stats{display:grid;grid-template-columns:repeat(3,1fr);padding:0;border-top:1px solid #252a27;border-bottom:0}.runtime-stats div{display:grid;gap:.45rem;padding:1rem 1.25rem}.runtime-stats div+div{border-left:1px solid #252a27}.runtime-stats span{color:#737b76;font-size:.57rem}.runtime-stats strong{color:#a7f0d0;font-size:.78rem}.receipt{display:inline-grid;gap:1rem;background:#0c2119;color:#b9f6da;border:1px solid var(--esaa);padding:1.5rem;font-family:var(--mono)}.receipt span{font-size:.7rem}.receipt code{line-height:1.7}.quick pre{font-size:clamp(.8rem,2vw,1.05rem);padding:2rem;background:#090908;border:1px solid #333;border-radius:12px;overflow:auto}.runner-grid article{display:grid}.runner-grid article>span{font-family:var(--mono);color:var(--esaa)}.runner-grid b{margin-top:3rem}.trust ul{list-style:none;padding:0;border-top:1px solid #444}.trust li{display:grid;grid-template-columns:1fr 2fr;padding:1.5rem 0;border-bottom:1px solid #444}.trust li span{color:#aaa}@keyframes livePulse{50%{opacity:.45;box-shadow:0 0 0 8px rgba(70,217,155,0)}}
 @media(max-width:800px){.esaa-nav{top:64px;justify-content:flex-start}.signal{overflow-x:auto}.principles,.runner-grid{grid-template-columns:1fr}.flow-box{align-items:stretch;flex-direction:column}.flow-box>span{transform:rotate(90deg);align-self:center}.runtime-stage{grid-template-columns:1fr}.runtime-main{border-right:0;border-bottom:1px solid #252a27}.animated-machine{grid-template-columns:repeat(2,1fr)}.animated-state:nth-child(2)::after{display:none}.event-stream li{grid-template-columns:65px 62px 1fr}.trust li{grid-template-columns:1fr;gap:.4rem}}
 @media(max-width:520px){.runtime-head{align-items:flex-start;gap:1rem;flex-direction:column}.animated-machine{grid-template-columns:1fr}.animated-state::after{display:none}.event-stream li{grid-template-columns:1fr;gap:.25rem;border-bottom:1px solid #202421}.runtime-stats{grid-template-columns:1fr}.runtime-stats div+div{border-left:0;border-top:1px solid #252a27}}
 @media(prefers-reduced-motion:reduce){.live-dot{animation:none}.animated-state,.event-stream li{transition:none}}
</style>
<script>
 const demos = document.querySelectorAll('[data-esaa-demo]');
 demos.forEach((demo) => {
  const locale = demo.getAttribute('data-locale');
  const states = ['todo','in_progress','review','done'];
  const agents = ['null','agent-impl','agent-qa','agent-qa'];
  const hashes = ['9f2a…71c0','a1d4…11e8','6bd9…dc02','e84f…3aa7'];
  const stateNodes = [...demo.querySelectorAll('[data-demo-state]')];
  const eventNodes = [...demo.querySelectorAll('[data-demo-event]')];
  const toggle = demo.querySelector('[data-demo-toggle]');
  const replay = demo.querySelector('[data-demo-replay]');
  let step = 0; let paused = false; let timer: number | undefined;
  const reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  const setText = (selector: string, value: string) => { const node = demo.querySelector<HTMLElement>(selector); if (node) node.textContent = value; };
  const render = () => {
   stateNodes.forEach((node,index) => { node.classList.toggle('is-active', index === step); node.classList.toggle('is-past', index < step); });
   eventNodes.forEach((node,index) => { node.classList.toggle('is-visible', index <= step); node.classList.toggle('is-current', index === step); });
   setText('[data-demo-status]', states[step]);
   setText('[data-roadmap-line]', `status: ${states[step]}`);
   setText('[data-roadmap-agent]', agents[step]);
   setText('[data-roadmap-seq]', String(1041 + step));
   setText('[data-roadmap-hash]', hashes[step]);
   setText('[data-event-count]', String(step + 1));
   setText('[data-count="todo"]', step === 0 ? '1' : '0');
   setText('[data-count="active"]', step === 1 ? '1' : '0');
   setText('[data-count="review"]', step === 2 ? '1' : '0');
   setText('[data-count="done"]', step === 3 ? '1' : '0');
  };
  const schedule = () => { clearInterval(timer); if (!paused && !reduced) timer = window.setInterval(() => { step = (step + 1) % states.length; render(); }, 2200); };
  toggle?.addEventListener('click', () => { paused = !paused; toggle.textContent = paused ? (locale === 'pt' ? 'Continuar' : 'Resume') : (locale === 'pt' ? 'Pausar' : 'Pause'); schedule(); });
  replay?.addEventListener('click', () => { step = 0; paused = false; if (toggle) toggle.textContent = locale === 'pt' ? 'Pausar' : 'Pause'; render(); schedule(); });
  render();
  const observer = new IntersectionObserver(([entry]) => { if (entry.isIntersecting) schedule(); else clearInterval(timer); }, { threshold: .2 });
  observer.observe(demo);
 });
</script>
